  1→/**
  2→ * API Configuration
  3→ * Central configuration for API endpoints and settings
  4→ *
  5→ * Supports dynamic port allocation in both Tauri app and web dev mode:
  6→ * - Tauri app: Uses Rust backend manager via invoke('get_backend_port')
  7→ * - Web dev: Uses VITE_BACKEND_PORT environment variable from dev.sh
  8→ * - Port Discovery: Tries to discover backend port by checking /api/health
  9→ * - Fallback: Port 3333 if neither is available
 10→ */
 11→
 12→import { invoke, isTauriEnv } from "@/platform/tauri";
 13→
 14→let cachedPort: number | null = null;
 15→let portPromise: Promise<number> | null = null;
 16→
 17→// Tauri IPC retry config for backend port resolution.
 18→// The backend may not have emitted its [BACKEND_PORT] marker yet during early
 19→// startup — Rust setup() blocks the main thread for up to 5s waiting for it,
 20→// and IPC calls from the webview are queued until setup completes.
 21→// 30 attempts × 200ms = 6s covers the 5s startup timeout with margin.
 22→const TAURI_PORT_MAX_RETRIES = 30;
 23→const TAURI_PORT_RETRY_DELAY_MS = 200;
 24→
 25→// Common ports to try during discovery (most recently used ports)
 26→// Backend uses PORT=0 for dynamic allocation, so we try a range of common ports
 27→const DISCOVERY_PORTS = [
 28→  51176,
 29→  52820,
 30→  53792, // Recent dynamic ports
 31→  59270,
 32→  59271,
 33→  59269, // Previous attempts
 34→  3333,
 35→  3334,
 36→  3335, // Default fallback range
 37→  8080,
 38→  8081,
 39→  8082, // Alternative common ports
 40→  50000,
 41→  50001,
 42→  50002,
 43→  50003,
 44→  50004,
 45→  50005, // Dynamic port range
 46→  51000,
 47→  51001,
 48→  51002,
 49→  51003,
 50→  51004,
 51→  51005, // More dynamic ports
 52→  52000,
 53→  52001,
 54→  52002,
 55→  52003,
 56→  52004,
 57→  52005, // More dynamic ports
 58→  53000,
 59→  53001,
 60→  53002,
 61→  53003,
 62→  53004,
 63→  53005, // More dynamic ports
 64→];
 65→
 66→/**
 67→ * Try to discover backend port by checking /api/health on common ports
 68→ */
 69→async function isBackendHealthResponse(response: Response): Promise<boolean> {
 70→  if (!response.ok) return false;
 71→  try {
 72→    const data = await response.json();
 73→    return data?.app === "opendevs-backend" && data?.status === "ok";
 74→  } catch {
 75→    return false;
 76→  }
 77→}
 78→
 79→async function discoverBackendPort(): Promise<number | null> {
 80→  // Try localStorage first (fastest)
 81→  const stored = localStorage.getItem("opendevs_backend_port");
 82→  if (stored) {
 83→    const port = parseInt(stored);
 84→    try {
 85→      const response = await fetch(`http://localhost:${port}/api/health`, {
 86→        method: "GET",
 87→        signal: AbortSignal.timeout(1000),
 88→      });
 89→      if (await isBackendHealthResponse(response)) {
 90→        if (import.meta.env.DEV) console.log(`[API] Found backend on stored port: ${port}`);
 91→        return port;
 92→      }
 93→    } catch (e) {
 94→      // Port changed, continue discovery
 95→    }
 96→  }
 97→
 98→  // Try discovery on common ports in parallel for speed
 99→  if (import.meta.env.DEV)
100→    console.log(`[API] Scanning ${DISCOVERY_PORTS.length} ports for backend...`);
101→
102→  const portChecks = DISCOVERY_PORTS.map(async (port) => {
103→    try {
104→      const controller = new AbortController();
105→      const timeoutId = setTimeout(() => controller.abort(), 500);
106→
107→      const response = await fetch(`http://localhost:${port}/api/health`, {
108→        method: "GET",
109→        signal: controller.signal,
110→      });
111→
112→      clearTimeout(timeoutId);
113→
114→      if (await isBackendHealthResponse(response)) {
115→        return port;
116→      }
117→    } catch (e) {
118→      // Port not available
119→    }
120→    return null;
121→  });
122→
123→  const results = await Promise.all(portChecks);
124→  const foundPort = results.find((port) => port !== null);
125→
126→  if (foundPort) {
127→    if (import.meta.env.DEV) console.log(`[API] Discovered backend on port: ${foundPort}`);
128→    localStorage.setItem("opendevs_backend_port", foundPort.toString());
129→    return foundPort;
130→  }
131→
132→  return null;
133→}
134→
135→/**
136→ * Get the backend port (cached after first call).
137→ *
138→ * In Tauri mode, retries the IPC call with backoff because the backend may
139→ * still be starting when the webview first loads. Without retries, a single
140→ * failed invoke permanently caches port 3333, causing all API requests to
141→ * hit the wrong port and leaving the window hidden.
142→ */
143→async function getBackendPort(): Promise<number> {
144→  if (cachedPort !== null) {
145→    return cachedPort;
146→  }
147→
148→  // If there's already a pending request, return it
149→  if (portPromise !== null) {
150→    return portPromise;
151→  }
152→
153→  portPromise = (async () => {
154→    // 1. Check if running in web dev mode with dynamic port
155→    if (import.meta.env.VITE_BACKEND_PORT) {
156→      const port = parseInt(import.meta.env.VITE_BACKEND_PORT as string, 10);
157→      if (!isNaN(port)) {
158→        if (import.meta.env.DEV) console.log(`[API] Using web dev backend port: ${port}`);
159→        cachedPort = port;
160→        return port;
161→      }
162→    }
163→
164→    // 2. Try Tauri API (for Tauri app mode) — retry with backoff.
165→    // The backend is managed by Rust and WILL start, but the port may not
166→    // be available yet if we're called before setup() finishes.
167→    if (isTauriEnv) {
168→      for (let attempt = 0; attempt < TAURI_PORT_MAX_RETRIES; attempt++) {
169→        try {
170→          const port = await invoke<number>("get_backend_port");
171→          if (import.meta.env.DEV) console.log(`[API] Using Tauri backend port: ${port} (attempt ${attempt + 1})`);
172→          cachedPort = port;
173→          return port;
174→        } catch {
175→          if (attempt < TAURI_PORT_MAX_RETRIES - 1) {
176→            await new Promise((resolve) => setTimeout(resolve, TAURI_PORT_RETRY_DELAY_MS));
177→          }
178→        }
179→      }
180→      // All retries exhausted — don't cache a wrong port. Throw so TanStack Query
181→      // retries the entire fetch later, giving the backend more time to start.
182→      console.error("[API] get_backend_port failed after retries — backend may not have started");
183→      throw new Error("Backend port not available after retries");
184→    }
185→
186→    // 3. Non-Tauri: single invoke attempt (will fail fast if not in Tauri)
187→    try {
188→      const port = await invoke<number>("get_backend_port");
189→      if (import.meta.env.DEV) console.log(`[API] Using Tauri backend port: ${port}`);
190→      cachedPort = port;
191→      return port;
192→    } catch {
193→      if (import.meta.env.DEV)
194→        console.log("[API] Tauri API not available, trying port discovery...");
195→    }
196→
197→    // 4. Try port discovery (for web browser accessing Vite dev server)
198→    const discoveredPort = await discoverBackendPort();
199→    if (discoveredPort) {
200→      if (import.meta.env.DEV)
201→        console.log(`[API] Using discovered backend port: ${discoveredPort}`);
202→      cachedPort = discoveredPort;
203→      return discoveredPort;
204→    }
205→
206→    // 5. Fallback to hardcoded port — do NOT cache so next call retries
207→    console.warn("[API] Could not discover backend port, falling back to default port 3333");
208→    return 3333;
209→  })();
210→
211→  // Clear promise when done (success or failure)
212→  portPromise.finally(() => {
213→    portPromise = null;
214→  });
215→
216→  return portPromise;
217→}
218→
219→/**
220→ * Get the base URL for API requests (async)
221→ */
222→export async function getBaseURL(): Promise<string> {
223→  const port = await getBackendPort();
224→  return `http://localhost:${port}/api`;
225→}
226→
227→export const API_CONFIG = {
228→  getBaseURL,
229→  POLL_INTERVAL: 2000, // 2 seconds
230→  REQUEST_TIMEOUT: 30000, // 30 seconds
231→} as const;
232→
233→export const ENDPOINTS = {
