  1→/**
  2→ * Chat Insert Store — typed Zustand store for dispatching content into the
  3→ * active chat input. Replaces the untyped CustomEvent("insert-to-chat")
  4→ * window event bus.
  5→ *
  6→ * Producers call chatInsertActions.insertText / insertFiles / insertElement
  7→ * from any component (BrowserPanel, DiffViewer, SimulatorPanel).
  8→ *
  9→ * The single consumer (MainLayout) subscribes to pending payloads and
 10→ * forwards them to the SessionPanel ref.
 11→ */
 12→
 13→import { create } from "zustand";
 14→import { devtools } from "zustand/middleware";
 15→import type { InspectElement } from "@/features/session/lib/parseInspectTags";
 16→
 17→/**
 18→ * Typed payloads for inserting content into the chat input.
 19→ *
 20→ * - text:    plain markdown (e.g., DiffViewer comment → chat)
 21→ * - files:   File objects (e.g., browser screenshot, simulator screenshot)
 22→ * - element: inspected DOM element metadata (e.g., BrowserPanel InSpec mode)
 23→ */
 24→export type ChatInsertPayload =
 25→  | { type: "text"; workspaceId: string; text: string }
 26→  | { type: "files"; workspaceId: string; files: File[] }
 27→  | { type: "element"; workspaceId: string; element: InspectElement };
 28→
 29→// SerializedChatInsertPayload is the Zod-inferred type from the event catalog.
 30→// The Zod schema validates the transport shape; the inferred type aligns with
 31→// InspectElement so no casting is needed at the boundary.
 32→import type { SerializedChatInsertPayload } from "@shared/events";
 33→export type { SerializedChatInsertPayload };
 34→
 35→export interface ChatInsertTarget {
 36→  insertText: (text: string) => void;
 37→  addFiles: (files: File[]) => void;
 38→  addInspectedElement: (element: InspectElement) => void;
 39→}
 40→
 41→interface ChatInsertState {
 42→  pending: ChatInsertPayload | null;
 43→  dispatch: (payload: ChatInsertPayload) => void;
 44→  consume: () => void;
 45→}
 46→
 47→export const useChatInsertStore = create<ChatInsertState>()(
 48→  devtools(
 49→    (set) => ({
 50→      pending: null,
 51→      dispatch: (payload) => set({ pending: payload }, false, "chatInsert/dispatch"),
 52→      consume: () => set({ pending: null }, false, "chatInsert/consume"),
 53→    }),
 54→    { name: "chat-insert-store", enabled: import.meta.env.DEV }
 55→  )
 56→);
 57→
 58→/** Stable actions for use outside React components */
 59→export const chatInsertActions = {
 60→  dispatch: (payload: ChatInsertPayload) => useChatInsertStore.getState().dispatch(payload),
 61→  insertText: (workspaceId: string, text: string) =>
 62→    useChatInsertStore.getState().dispatch({ type: "text", workspaceId, text }),
 63→  insertFiles: (workspaceId: string, files: File[]) =>
 64→    useChatInsertStore.getState().dispatch({ type: "files", workspaceId, files }),
 65→  insertElement: (workspaceId: string, element: InspectElement) =>
 66→    useChatInsertStore.getState().dispatch({ type: "element", workspaceId, element }),
 67→  consume: () => useChatInsertStore.getState().consume(),
 68→};
 69→
 70→export function isChatInsertForWorkspace(
 71→  payload: ChatInsertPayload,
 72→  activeWorkspaceId: string | null | undefined
 73→): boolean {
 74→  return !!activeWorkspaceId && payload.workspaceId === activeWorkspaceId;
 75→}
 76→
 77→export function deliverChatInsertPayload(
 78→  target: ChatInsertTarget,
 79→  payload: ChatInsertPayload
 80→): void {
 81→  switch (payload.type) {
 82→    case "text":
 83→      target.insertText(payload.text);
 84→      return;
 85→    case "files":
 86→      target.addFiles(payload.files);
 87→      return;
 88→    case "element":
 89→      target.addInspectedElement(payload.element);
 90→      return;
 91→  }
 92→}
 93→
 94→function bytesToBase64(bytes: Uint8Array): string {
 95→  if (typeof Buffer !== "undefined") {
 96→    return Buffer.from(bytes).toString("base64");
 97→  }
 98→
 99→  let binary = "";
100→  const chunkSize = 0x8000;
101→  for (let i = 0; i < bytes.length; i += chunkSize) {
102→    binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
103→  }
104→  return btoa(binary);
105→}
106→
107→function base64ToBytes(base64: string): Uint8Array {
108→  if (typeof Buffer !== "undefined") {
109→    return Uint8Array.from(Buffer.from(base64, "base64"));
110→  }
111→
112→  const binary = atob(base64);
113→  const bytes = new Uint8Array(binary.length);
114→  for (let i = 0; i < binary.length; i++) {
115→    bytes[i] = binary.charCodeAt(i);
116→  }
117→  return bytes;
118→}
119→
120→export async function serializeChatInsertPayload(
121→  payload: ChatInsertPayload
122→): Promise<SerializedChatInsertPayload> {
123→  switch (payload.type) {
124→    case "text":
125→      return payload;
126→    case "element":
127→      return payload;
128→    case "files":
129→      return {
130→        type: "files",
131→        workspaceId: payload.workspaceId,
132→        files: await Promise.all(
133→          payload.files.map(async (file) => ({
134→            name: file.name,
135→            type: file.type,
136→            lastModified: file.lastModified,
137→            base64: bytesToBase64(new Uint8Array(await file.arrayBuffer())),
138→          }))
139→        ),
140→      };
141→  }
142→}
143→
144→export async function deserializeChatInsertPayload(
145→  payload: SerializedChatInsertPayload
146→): Promise<ChatInsertPayload> {
147→  switch (payload.type) {
148→    case "text":
149→      return payload;
150→    case "element":
151→      return payload;
152→    case "files":
153→      return {
154→        type: "files",
155→        workspaceId: payload.workspaceId,
156→        files: payload.files.map((file) => {
157→          const bytes = Uint8Array.from(base64ToBytes(file.base64));
158→          return new File([bytes], file.name, {
159→            type: file.type,
160→            lastModified: file.lastModified,
161→          });
162→        }),
163→      };
164→  }
165→}
