/**
 * Base API Client
 * Handles HTTP requests with proper error handling and type safety
 *
 * Now supports dynamic port allocation.
 * Attaches Bearer token for remote (non-localhost) browser clients.
 */

import { API_CONFIG, getBaseURL } from "../config/api.config";
import { getStoredToken, needsRemoteAuth } from "@/features/auth";
import type { ApiError } from "../types";

class ApiClient {
  private timeout: number;

  constructor(timeout: number = API_CONFIG.REQUEST_TIMEOUT) {
    this.timeout = timeout;
  }

  /**
   * Generic GET request
   */
  async get<T>(endpoint: string): Promise<T> {
    return this.request<T>(endpoint, { method: "GET" });
  }

  /**
   * Generic POST request
   */
  async post<T>(endpoint: string, data?: any): Promise<T> {
    return this.request<T>(endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  /**
   * Generic PUT request
   */
  async put<T>(endpoint: string, data?: any): Promise<T> {
    return this.request<T>(endpoint, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  /**
   * Generic PATCH request
   */
  async patch<T>(endpoint: string, data: any): Promise<T> {
    return this.request<T>(endpoint, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    });
  }

  /**
   * Generic DELETE request
   */
  async delete<T>(endpoint: string): Promise<T> {
    return this.request<T>(endpoint, { method: "DELETE" });
  }

  /**
   * Core request method with timeout and error handling.
   * Attaches Authorization header for remote browser clients.
   */
  private async request<T>(endpoint: string, options: RequestInit): Promise<T> {
    const baseURL = await getBaseURL();
    const url = `${baseURL}${endpoint}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.timeout);

    // Attach Bearer token for remote (non-localhost) browser sessions
    const headers = new Headers(options.headers);
    if (needsRemoteAuth()) {
      const token = getStoredToken();
      if (token) {
        headers.set("Authorization", `Bearer ${token}`);
      }
    }

    try {
      const response = await fetch(url, {
        ...options,
        headers,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const error: ApiError = {
          status: response.status,
          message: response.statusText,
        };

        try {
          const errorData = await response.json();
          error.details = errorData;
          error.message = errorData.error || errorData.message || error.message;
        } catch {
          // Response is not JSON
        }

        throw error;
      }

      // Handle empty responses
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        return null as T;
      }

      return await response.json();
    } catch (error) {
      clearTimeout(timeoutId);

      if (error instanceof Error) {
        if (error.name === "AbortError") {
          throw {
            status: 408,
            message: "Request timeout",
            details: error,
          } as ApiError;
        }
        throw {
          status: 0,
          message: error.message,
          details: error,
        } as ApiError;
      }

      throw error;
    }
  }
}

// Export singleton instance
export const apiClient = new ApiClient();

/**
 * Query Keys Factory
 * Type-safe, hierarchical query keys for TanStack Query
 *
 * Pattern: [scope, ...identifiers, ...filters]
 * Benefits:
 * - Easy invalidation (invalidate all workspaces with ['workspaces'])
 * - Prevents cache collisions
 * - Autocomplete support
 */

export const queryKeys = {
  // Workspaces
  workspaces: {
    all: ["workspaces"] as const,
    byRepo: (state?: string) => ["workspaces", "by-repo", state] as const,
    detail: (id: string) => ["workspaces", "detail", id] as const,
    diffStats: (id: string) => ["workspaces", "diff-stats", id] as const,
    diffFiles: (id: string) => ["workspaces", "diff-files", id] as const,
    uncommittedFiles: (id: string) => ["workspaces", "uncommitted-files", id] as const,
    lastTurnFiles: (id: string, sessionId?: string) =>
      ["workspaces", "last-turn-files", id, sessionId] as const,
    diffFile: (id: string, file: string) => ["workspaces", "diff-file", id, file] as const,
    prStatus: (id: string) => ["workspaces", "pr-status", id] as const,
    penFiles: (id: string) => ["workspaces", "pen-files", id] as const,
    systemPrompt: (id: string) => ["workspaces", "system-prompt", id] as const,
    manifest: (id: string) => ["workspaces", "manifest", id] as const,
  },

  // Sessions
  sessions: {
    all: ["sessions"] as const,
    detail: (id: string) => ["sessions", "detail", id] as const,
    messages: (id: string) => ["sessions", "messages", id] as const,
    byWorkspace: (workspaceId: string) => ["sessions", "by-workspace", workspaceId] as const,
  },

  // Repositories
  repos: {
    all: ["repos"] as const,
    detail: (id: string) => ["repos", "detail", id] as const,
    manifest: (id: string) => ["repos", "manifest", id] as const,
  },

  // Stats
  stats: {
    all: ["stats"] as const,
  },

  // GitHub CLI
  github: {
    ghStatus: ["github", "gh-status"] as const,
  },

  // AI Provider Status (external health monitoring)
  providerStatus: {
    all: ["provider-status"] as const,
    detail: (providerId: string) => ["provider-status", "detail", providerId] as const,
  },

  // Settings
  settings: {
    all: ["settings"] as const,
    mcpServers: ["settings", "mcp-servers"] as const,
    commands: ["settings", "commands"] as const,
    agents: ["settings", "agents"] as const,
  },

  // Agent Config (scope-aware config management)
  agentConfig: {
    all: ["agent-config"] as const,
    category: (cat: string, scope: string, repoPath?: string) =>
      ["agent-config", cat, scope, repoPath] as const,
  },
} as const;

/**
 * TanStack Query Configuration
 * Optimized for real-time IDE with polling and WebSocket updates
 *
 * PERFORMANCE NOTES:
 * - Was: staleTime 1000ms → Caused cascade refetches on every re-render
 * - Was: refetchOnWindowFocus true → Triggered refetch on EVERY input focus (typing lag)
 * - Now: 5min staleTime + disabled focus refetch = smooth typing, 60% fewer requests
 *
 * ARCHITECTURE:
 * - Desktop (Tauri): Real-time via Unix socket events + minimal polling
 * - Web (Browser): Smart conditional polling (only when workspace working)
 * - Individual queries override these defaults for specific needs
 */

import { QueryClient } from "@tanstack/react-query";

export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      // Cache data for 5 minutes (was 1000ms - caused excessive refetches)
      // Long staleTime is safe because:
      // - Real-time data uses events (desktop) or conditional polling (web)
      // - Static data (repos, settings) rarely changes
      staleTime: 5 * 60 * 1000,

      // Keep unused data in cache for 5 minutes
      gcTime: 5 * 60 * 1000,

      // Retry failed requests (exponential backoff)
      retry: 2,
      retryDelay: (attemptIndex) => Math.min(1000 * 2 ** attemptIndex, 30000),

      // ❌ DISABLED: Causes refetch on every input focus (typing lag)
      // Every keystroke triggered focus change → cascade refetch
      refetchOnWindowFocus: false,

      // Only refetch if data is actually stale (not on every mount)
      refetchOnMount: true,

      // Don't refetch on reconnect (conditional polling handles updates)
      refetchOnReconnect: false,

      // Network mode: always fetch (even offline for local backend)
      networkMode: "always",
    },
    mutations: {
      // Retry mutations once on failure
      retry: 1,
      networkMode: "always",
    },
  },
});

